public class ArithmeticEdgeCases {
    public static void main(String[] args) {
        // Integer division truncates toward zero
        System.out.println(7 / 2);     // 3
        System.out.println(-7 / 2);    // -3  (NOT -4 — truncates TOWARD zero)
        System.out.println(7 / -2);    // -3
        System.out.println(-7 / -2);   // 3

        // Modulo: sign follows LEFT operand (dividend)
        System.out.println(7 % 3);     // 1
        System.out.println(-7 % 3);    // -1  (sign is negative, from dividend)
        System.out.println(7 % -3);    // 1   (sign is positive, from dividend)
        System.out.println(-7 % -3);   // -1

        // Floating-point division by zero — no exception!
        System.out.println(1.0 / 0.0);  // Infinity
        System.out.println(-1.0 / 0.0); // -Infinity
        System.out.println(0.0 / 0.0);  // NaN  (Not a Number)

        // Integer division by zero — throws ArithmeticException!
        // System.out.println(1 / 0);   // RUNTIME ERROR

        // Floating point precision
        System.out.println(0.1 + 0.2); // 0.30000000000000004 (not 0.3!)
    }
}

public class EqualityDemo {
    public static void main(String[] args) {
        // Primitives: == compares VALUES
        int a = 5, b = 5;
        System.out.println(a == b);   // true

        // Strings: == compares REFERENCES (memory addresses)
        String s1 = "hello";          // String pool
        String s2 = "hello";          // Same pool object
        String s3 = new String("hello"); // NEW object on heap

        System.out.println(s1 == s2);      // true  (both from pool)
        System.out.println(s1 == s3);      // false (different objects)
        System.out.println(s1.equals(s3)); // true  (same content)

        // null comparison — always use ==
        String name = null;
        System.out.println(name == null);  // true  (correct way)
        // System.out.println(name.equals(null)); // NullPointerException!

        // Comparing with literal on left — null-safe style
        System.out.println("hello".equals(name)); // false (no NPE)
    }
}

public class ShortCircuitDemo {
    static int counter = 0;

    static boolean check(boolean val) {
        counter++;   // Side effect: increments counter
        return val;
    }

    public static void main(String[] args) {
        // Short-circuit &&: if left is false, right not evaluated
        counter = 0;
        boolean r1 = check(false) && check(true);
        System.out.println(counter); // 1  (only left side called)

        // Short-circuit ||: if left is true, right not evaluated
        counter = 0;
        boolean r2 = check(true) || check(false);
        System.out.println(counter); // 1  (only left side called)

        // Eager &: both always evaluated
        counter = 0;
        boolean r3 = check(false) & check(true);
        System.out.println(counter); // 2  (both sides called)

        // Null-safety with short-circuit
        String s = null;
        // Safe: if s==null, the .length() is never called
        if (s != null && s.length() > 0) {
            System.out.println("Not empty");
        } else {
            System.out.println("Null or empty"); // This prints
        }
    }
}

public class BitwiseDemo {
    public static void main(String[] args) {
        int a = 12;  // binary: 0000 1100
        int b = 10;  // binary: 0000 1010

        System.out.println(a & b);   // AND:  0000 1000 = 8
        System.out.println(a | b);   // OR:   0000 1110 = 14
        System.out.println(a ^ b);   // XOR:  0000 0110 = 6
        System.out.println(~a);      // NOT:  1111 0011 = -13  (two's complement)

        // Shift operators
        System.out.println(a << 1);  // Left shift 1: 0001 1000 = 24  (multiply by 2)
        System.out.println(a >> 1);  // Signed right shift: 0000 0110 = 6 (divide by 2)
        System.out.println(a >>> 1); // Unsigned right shift: 0000 0110 = 6

        // Negative number right shift
        int neg = -16;  // 1111 0000 (two's complement)
        System.out.println(neg >> 1);  // -8   (>> preserves sign bit)
        System.out.println(neg >>> 1); // 2147483640  (>>> fills with 0)

        // Useful bit tricks
        System.out.println(a & 1);    // 0 = even  (check last bit)
        System.out.println(b & 1);    // 0 = even
        System.out.println(7 & 1);    // 1 = odd
    }
}

public class TernaryDemo {
    public static void main(String[] args) {
        int x = 7;

        // Basic usage
        String parity = (x % 2 == 0) ? "even" : "odd";
        System.out.println(parity);    // odd

        // Nested ternary (right-associative)
        int score = 75;
        String grade = score >= 90 ? "A" : score >= 75 ? "B" : score >= 60 ? "C" : "F";
        System.out.println(grade);     // B

        // Ternary with type promotion — TRICKY!
        int i = 1;
        System.out.println(true ? 1 : 2.0);  // 1.0  NOT 1!
        // Both branches must be compatible. int 1 promotes to double 1.0

        // Ternary in concatenation
        int age = 20;
        System.out.println("You are " + (age >= 18 ? "adult" : "minor"));
        // "You are adult"

        // Without parentheses — precedence trap!
        System.out.println("Value: " + age >= 18 ? "adult" : "minor");
        // NOT "Value: adult". Reason:
        // + has HIGHER precedence than ?:
        // Evaluates as: ("Value: " + age) >= 18 ? "adult" : "minor"
        // = "Value: 20" >= 18 — comparing String to int — COMPILE ERROR
    }
}

public class CompoundAssign {
    public static void main(String[] args) {
        // Compound = operator + implicit cast
        byte b = 10;
        b += 5;   // OK: equivalent to b = (byte)(b + 5)  → 15
        System.out.println(b); // 15

        // Without compound, explicit cast needed:
        // b = b + 5;  // COMPILE ERROR: int cannot convert to byte
        b = (byte)(b + 5);  // Manual equivalent
        System.out.println(b); // 20

        // Multiple assignment (right to left)
        int x, y, z;
        x = y = z = 10;   // z=10, then y=10, then x=10
        System.out.println(x + " " + y + " " + z); // 10 10 10

        // DANGEROUS: assignment inside condition (legal but tricky)
        int n = 5;
        // if (n = 0)  // COMPILE ERROR: int in boolean context
        // BUT this works if the assigned value is boolean:
        boolean flag;
        boolean result;
        if (result = (n > 3)) {   // assigns AND tests
            System.out.println("n > 3, result = " + result); // prints
        }
    }
}

public class Q1 {
    public static void main(String[] args) {
        int a = 10, b = 3, c = 2;
        System.out.println(a + b * c);       // Line A
        System.out.println((a + b) * c);     // Line B
        System.out.println(a - b - c);       // Line C  (left to right)
        System.out.println(a % b + c * b);   // Line D
        System.out.println(a > b ? a : b);   // Line E
    }
}

public class Q2 {
    static int x = 0;
    static boolean inc() { x++; return true; }
    static boolean dec() { x--; return false; }

    public static void main(String[] args) {
        x = 0;
        boolean r1 = dec() && inc();   // Line A
        System.out.println(x);         // Line B

        x = 0;
        boolean r2 = inc() || dec();   // Line C
        System.out.println(x);         // Line D

        x = 0;
        boolean r3 = dec() & inc();    // Line E (eager)
        System.out.println(x);         // Line F
    }
}

public class Q3 {
    public static void main(String[] args) {
        int a = 15;  // 1111
        int b = 9;   // 1001

        System.out.println(a & b);   // A
        System.out.println(a | b);   // B
        System.out.println(a ^ b);   // C
        System.out.println(~a);      // D
        System.out.println(b << 2);  // E
        System.out.println(b >> 1);  // F
    }
}

public class Q4 {
    public static void main(String[] args) {
        int x = 50;
        String s = x > 90 ? "A" : x > 75 ? "B" : x > 60 ? "C" : x > 40 ? "D" : "F";
        System.out.println(s);

        // Type promotion in ternary
        System.out.println(true  ? 42 : 42.5);  // A
        System.out.println(false ? 42 : 42.5);  // B

        int a = 5, b = 10;
        int min = (a < b) ? a : b;
        System.out.println(min);
    }
}

