public class ExprErrors {
    public static void main(String[] args) {
        int a = 5, b = 0;

        // Fix 1: use short-circuit &&
        if (b != 0 && a / b > 2) {          // safe: b/0 never reached
            System.out.println("Big");
        }

        // Fix 2: use == for comparison
        boolean x = true, y = false;
        if (x == true && y == false) {       // or simply: if (x && !y)
            System.out.println("Both");       // prints
        }

        // Fix 3: use epsilon comparison
        double d1 = 0.1 + 0.2;
        if (Math.abs(d1 - 0.3) < 1e-9) {    // tolerance-based comparison
            System.out.println("Equal");      // prints
        }
    }
}

